import React, { useEffect, useState } from 'react'
import { Avatar, Box, Card, CardContent, CardHeader, List, ListItem, ListItemIcon, ListItemText, makeStyles, Paper, Typography } from '@material-ui/core'
import Cookies from 'js-cookie'

import axios from 'axios'
import { Link } from 'react-router-dom'
import { FiberManualRecordRounded } from '@material-ui/icons'

const useStyle = makeStyles((theme) => {
    return {
        root: {
            '& .MuiCard-root': {
                transform: 'none',
                '&:hover': {
                    transform: 'none',
                    boxShadow: 'none',
                    backgroundColor: 'rgba(0,0,0,0.03)',
                  }
            }
        },
        cardLink: {
            textDecoration: 'none',
            color: 'inherit'
        },
        list: {
            border: '1px solid rgba(0,0,0,0.2)',
            borderRadius: '5px',
            marginTop: theme.spacing(2)
        }
    }
})

export default function StudentPosts({ activity, img }) {
    const classes = useStyle()

    const file = JSON.parse(activity.files)

    const filesCollection = [];

    for (const key in file) {
        filesCollection.push(
            <ListItem className={classes.list} key={key}>
                <ListItemText>{`${file[key]}`}</ListItemText>
            </ListItem>
        );
    }


    return (
        <Box className={classes.root}>
            <Link className={classes.cardLink} to={`/studentActivity/${activity.id}`}>
                <Card className={classes.root} variant='outlined'>
                    <CardHeader avatar={
                        <Avatar src={img} />
                    }
                        title={activity.nameWhoPosted}
                    />
                    <CardContent>
                        
                        
                        <Typography variant='h6'>
                            {activity.title}
                        </Typography>
                        <Typography variant='body2' >
                            {activity.body}
                        </Typography>

                        <List disablePadding dense>{filesCollection}</List>

                    </CardContent>
                </Card>
                <br />
            </Link>
        </Box>
    )
}
